
-- Insert 28 FBK brake pad products
ON CONFLICT (sku) DO UPDATE SET
  erp_item_code = EXCLUDED.erp_item_code,
  name_ar = EXCLUDED.name_ar,
  base_price = EXCLUDED.base_price,
  category_id = EXCLUDED.category_id,
  image_url = EXCLUDED.image_url,
  is_active = true;

-- Insert wholesale tier1 prices for all FBK products
SELECT p.id, 'wholesale_tier1', v.wholesale_price
FROM (VALUES
  ('FD0044S-FBK', 345), ('FD9039MS-FBK', 349), ('IBKD2183', 365), ('FD2308S-FBK', 545),
  ('IBKD2330M', 460), ('FD2140MS-FBK', 575), ('FD2148MS-FBK', 575), ('FD2104S-FBK', 365),
  ('FD2314MS-FBK', 595), ('IBKD2303', 415), ('04465-0K420-IBK', 470), ('IBKD2310M', 495),
  ('FD2893MS-FBK', 565), ('IBKD2252', 395), ('FK0801-FBK', 375), ('FD2900S-FBK', 355),
  ('IBKD2254M', 365), ('IBKD2299', 410), ('FK2329R-FBK', 1495), ('FD2173MS-FBK', 365),
  ('K2378-FBK', 625), ('IBKD2374', 410), ('IBK2282', 825), ('IBK2335', 795),
  ('FK2335P-FBK', 795), ('FK2837-FBK', 925), ('IBK2427', 875), ('FK2510-FBK', 750)
) AS v(sku, wholesale_price)
JOIN products p ON p.sku = v.sku
ON CONFLICT (product_id, tier) DO UPDATE SET price = EXCLUDED.price;
